sql:
SELECT games.game_name, game_details.score_a, game_details.score_b
FROM games
JOIN game_details ON games.game_id = game_details.game_id;

SELECT predictor_name, affiliation
FROM predictors
WHERE experience = (
    SELECT MAX(experience)
    FROM predictors
);

SELECT predictors.predictor_name, predictor_affiliations.organization_name
FROM predictors
JOIN predictor_affiliations ON predictors.predictor_id = predictor_affiliations.predictor_id;

SELECT g.game_name, gd.team_a, gd.team_b, ABS(gd.score_a - gd.score_b) AS score_difference
FROM games g
JOIN game_details gd ON g.game_id = gd.game_id;

SELECT predictor_id, predictor_name, predictor_type, affiliation, experience, photo, bio, created_at, updated_at
FROM predictors
WHERE predictor_id = 1;

SELECT DISTINCT p.predictor_name, p.affiliation 
FROM predictors p
INNER JOIN predictions pr ON p.predictor_id = pr.predictor_id;

SELECT predictor_name 
FROM predictors
ORDER BY predictor_name;

